import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as i,e as n}from"./app-9f991d3d.js";const t={},o=n('<h1 id="cloud-service-model" tabindex="-1"><a class="header-anchor" href="#cloud-service-model" aria-hidden="true">#</a> Cloud Service Model</h1><p>常见的五大云服务模式</p><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/2e4218444fc64.png" alt="1709205332804.png" tabindex="0" loading="lazy"><figcaption>1709205332804.png</figcaption></figure><ul><li>Infrastructure as a service (laas): A form of cloud computing that delivers <u>fundamental compute, network, and storage resources to consumers on-demand</u>, over the internet, and on a <strong>pay-as-you-go basis</strong>.</li><li>Platform as a service (paas): Provides customers <strong>a development and hosting platform</strong> for <u>deploying customer-created applications</u>.</li><li>Software as a service (saas): A model of software deployment where an <strong>application is hosted (in a cloud center) as a service</strong> provided to customers across the internet.</li></ul><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/9834d66a78b92.png" alt="1709206766053.png" tabindex="0" loading="lazy"><figcaption>1709206766053.png</figcaption></figure><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/ecc0128a8abc5.png" alt="1709206983587.png" tabindex="0" loading="lazy"><figcaption>1709206983587.png</figcaption></figure><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/de0c3a0836956.png" alt="1709207014300.png" tabindex="0" loading="lazy"><figcaption>1709207014300.png</figcaption></figure><ul><li>laas：亚马逊弹性计算云（ec2）、谷歌计算引擎（gce）、微软azure laas、阿里巴巴云弹性计算服务（ecs）、.NET、微软云计算服务（laas）。</li><li>Caas（laas 的另一种形式）：亚马逊弹性容器服务（ecs）、谷歌 kubernetes 引擎（gke）、docker 云、azure kubernetes 服务（aks）、腾讯 kubernetes 引擎</li><li>Paas：谷歌应用程序引擎（gae），aws 弹性beanstalk，微软azure，..</li><li>Faas（“轻量级 paas”）：aws lambda、google 云函数、azure 函数、ibm 云函数。</li></ul><img src="https://pic.hanjiaming.com.cn/2024/02/29/3d0eb441ce1dc.png" alt="1709207174763.png" style="zoom:33%;">',9),s=[o];function c(r,l){return e(),i("div",null,s)}const d=a(t,[["render",c],["__file","csm.html.vue"]]);export{d as default};
